acms.artifact_envelope.v1.json (strict JSON Schema)



{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "acms.artifact_envelope.v1",
  "title": "ACMS Artifact Envelope v1",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "artifact_id",
    "schema_id",
    "schema_version",
    "run_id",
    "produced_at",
    "artifact",
    "provenance",
    "process_identity"
  ],
  "properties": {
    "artifact_id": {
      "type": "string",
      "pattern": "^sha256:[a-f0-9]{64}$"
    },
    "schema_id": {
      "type": "string",
      "const": "acms.artifact_envelope.v1"
    },
    "schema_version": {
      "type": "string",
      "pattern": "^\\d+\\.\\d+\\.\\d+$"
    },
    "run_id": {
      "type": "string",
      "pattern": "^(RUN|run)_[A-Za-z0-9._-]{8,128}$"
    },
    "produced_at": {
      "type": "string",
      "format": "date-time"
    },
    "artifact": {
      "type": "object",
      "additionalProperties": false,
      "required": ["path", "sha256"],
      "properties": {
        "path": {
          "type": "string",
          "minLength": 1
        },
        "sha256": {
          "type": "string",
          "pattern": "^sha256:[a-f0-9]{64}$"
        }
      }
    },
    "provenance": {
      "type": "object",
      "additionalProperties": false,
      "required": ["produced_by", "derived_from_artifacts", "transformation_rule"],
      "properties": {
        "produced_by": {
          "type": "object",
          "additionalProperties": false,
          "required": ["type", "id", "attempt"],
          "properties": {
            "type": {
              "type": "string",
              "enum": ["phase", "gate", "heal"]
            },
            "id": {
              "type": "string",
              "minLength": 1
            },
            "attempt": {
              "type": "integer",
              "minimum": 1,
              "maximum": 9999
            }
          }
        },
        "derived_from_artifacts": {
          "type": "array",
          "minItems": 0,
          "items": {
            "type": "object",
            "additionalProperties": false,
            "required": ["path", "sha256"],
            "properties": {
              "path": {
                "type": "string",
                "minLength": 1
              },
              "sha256": {
                "type": "string",
                "pattern": "^sha256:[a-f0-9]{64}$"
              }
            }
          }
        },
        "transformation_rule": {
          "type": "string",
          "minLength": 1
        }
      }
    },
    "process_identity": {
      "type": "object",
      "additionalProperties": false,
      "required": ["semantic_version", "logic_hash"],
      "properties": {
        "semantic_version": {
          "type": "string",
          "pattern": "^\\d+\\.\\d+\\.\\d+$"
        },
        "logic_hash": {
          "type": "string",
          "pattern": "^sha256:[a-f0-9]{64}$"
        }
      }
    }
  }
}



